import { useEffect, useState, useCallback } from 'react'
import { usePiRpc } from './hooks/usePiRpc'
import { useSessionManager } from './hooks/useSessionManager'
import ChatView from './components/ChatView'
import InputBar from './components/InputBar'
import SessionSidebar from './components/SessionSidebar'
import type { ViewMode } from './utils/compact-view'

function getDisplayName(session: { name: string | null; createdAt: string }): string {
  if (session.name) return session.name
  const d = new Date(session.createdAt)
  const month = d.toLocaleString('en', { month: 'short' })
  const day = d.getDate()
  const hh = String(d.getHours()).padStart(2, '0')
  const mm = String(d.getMinutes()).padStart(2, '0')
  return `${month} ${day} ${hh}:${mm}`
}

function App(): React.ReactElement {
  const { messages, isConnected, isStreaming, sendPrompt, abort, pendingUiRequests, respondToUiRequest, clearMessages, loadHistory, forkPoints, loadForkPoints, setOnAgentEnd } = usePiRpc()
  const { sessions, currentSession, forkAtEntry, switchSession, newSession, renameSession, deleteSession, getForkMessages, clearSession, refresh } = useSessionManager(isConnected)
  const [error, setError] = useState<string | null>(null)
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false)
  const [activeSessionPath, setActiveSessionPath] = useState<string | null>(null)
  const [viewMode, setViewMode] = useState<ViewMode>(() => {
    return (localStorage.getItem('xi-view-mode') as ViewMode) || 'normal'
  })

  const activeSession = activeSessionPath
    ? sessions?.projects?.flatMap(p => p.allSessions).find(s => s.filePath === activeSessionPath)
    : currentSession

  const activeSessionName = activeSession ? getDisplayName(activeSession) : null

  async function handleConnect(): Promise<void> {
    setError(null)
    const result = await window.api.start()
    if (!result.ok && result.error) {
      setError(result.error)
    }
    refresh()
  }

  // Auto-start Pi on mount
  useEffect(() => {
    handleConnect()
  }, [])

  const handleSwitchSession = useCallback(async (sessionPath: string) => {
    const prevPath = activeSessionPath
    setActiveSessionPath(sessionPath)
    const result = await switchSession(sessionPath)
    if (result.success) {
      clearMessages()
      await loadHistory()
      await loadForkPoints(sessionPath)
      await refresh()
    } else {
      setActiveSessionPath(prevPath)
    }
  }, [activeSessionPath, clearMessages, switchSession, loadHistory, loadForkPoints, refresh])

  const handleNewSession = useCallback(async (name: string) => {
    const parentPath = currentSession?.filePath
    clearMessages()
    const result = await newSession(name, parentPath)
    if (result) await refresh()
  }, [clearMessages, newSession, currentSession, refresh])

  const handleForkAtEntry = useCallback(async (entryId: string, name: string) => {
    clearMessages()
    await forkAtEntry(entryId, name)
    await loadHistory()
    await refresh()
  }, [clearMessages, forkAtEntry, loadHistory, refresh])

  const handleClearSession = useCallback(async () => {
    clearMessages()
    const ok = await clearSession()
    if (ok) {
      clearMessages()
      await loadHistory()
      await refresh()
      setActiveSessionPath(null)
    }
  }, [clearMessages, clearSession, loadHistory, refresh])

  useEffect(() => {
    if (isConnected) {
      loadHistory()
    }
  }, [isConnected, loadHistory])

  useEffect(() => {
    if (isConnected && currentSession?.filePath) {
      loadForkPoints(currentSession.filePath)
    }
  }, [isConnected, currentSession?.filePath, loadForkPoints])

  useEffect(() => {
    setOnAgentEnd(() => refresh)
  }, [setOnAgentEnd, refresh])

  useEffect(() => {
    function handleKeyDown(e: KeyboardEvent): void {
      if (e.key === 'Escape' && isStreaming) {
        abort()
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [isStreaming, abort])

  useEffect(() => {
    const cleanup = window.api.onEvent((rawEvent) => {
      const evt = rawEvent as { type: string; error?: string; errorMessage?: string }
      if (evt.type === 'extension_error' && evt.error) {
        setError(`Extension error: ${evt.error}`)
      }
    })
    return cleanup
  }, [])

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-white text-gray-900">
      <SessionSidebar
        sessions={sessions}
        currentSession={currentSession}
        onSwitchSession={handleSwitchSession}
        onNewSession={handleNewSession}
        onRenameSession={renameSession}
        onDeleteSession={deleteSession}
        isCollapsed={sidebarCollapsed}
        onToggleCollapse={() => setSidebarCollapsed(!sidebarCollapsed)}
      />

      <div className="flex flex-1 flex-col overflow-hidden">
        <div className="flex items-center justify-between border-b border-gray-200 bg-gray-50 px-4 pt-10 pb-2" style={{ WebkitAppRegion: 'drag' } as React.CSSProperties}>
          <div className="flex items-center gap-2" style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            {sidebarCollapsed && (
              <button
                onClick={() => setSidebarCollapsed(false)}
                className="rounded p-1 text-gray-500 hover:text-gray-700 hover:bg-gray-100 transition-colors"
                title="Show sessions"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M4 6h16M4 12h16M4 18h16" />
                </svg>
              </button>
            )}
            <div className={`h-2 w-2 rounded-full ${isConnected ? 'bg-green-500' : 'bg-red-500'}`} />
            <span className="text-xs text-gray-600">
              {isConnected ? 'Pi Connected' : 'Pi Disconnected'}
            </span>
            {activeSessionName && (
              <>
                <span className="text-xs text-gray-700 font-medium border-l border-gray-300 pl-2">
                  {activeSessionName}
                </span>
                <button
                  onClick={handleClearSession}
                  className="rounded p-1 text-gray-400 hover:text-red-500 hover:bg-gray-100 transition-colors"
                  title="Clear conversation"
                >
                  <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                </button>
              </>
            )}
            {isStreaming && (
              <span className="text-xs text-blue-600 animate-pulse">Streaming...</span>
            )}
            {error && (
              <span className="text-xs text-red-500" title={error}>Error</span>
            )}
          </div>
          <div className="flex items-center rounded-md border border-gray-200 bg-gray-100 p-0.5" style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            <button
              onClick={() => { localStorage.setItem('xi-view-mode', 'normal'); setViewMode('normal') }}
              className={`rounded px-2 py-0.5 text-xs font-medium transition-colors ${viewMode === 'normal' ? 'bg-gray-200 text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
              title="Full view"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 4h18M3 8h18M3 12h18M3 16h18M3 20h18" />
              </svg>
            </button>
            <button
              onClick={() => { localStorage.setItem('xi-view-mode', 'turn'); setViewMode('turn') }}
              className={`rounded px-2 py-0.5 text-xs font-medium transition-colors ${viewMode === 'turn' ? 'bg-gray-200 text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
              title="Turn view"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 5h18M6 9h12M3 13h18M6 17h12" />
              </svg>
            </button>
            <button
              onClick={() => { localStorage.setItem('xi-view-mode', 'outline'); setViewMode('outline') }}
              className={`rounded px-2 py-0.5 text-xs font-medium transition-colors ${viewMode === 'outline' ? 'bg-gray-200 text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
              title="Outline view"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 7h18M3 12h18M3 17h18" />
              </svg>
            </button>
          </div>
          <div className="flex items-center gap-2" style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            {!isConnected && (
              <button
                onClick={handleConnect}
                className="rounded bg-blue-600 px-3 py-1 text-xs font-medium text-white hover:bg-blue-500"
              >
                Connect to Pi
              </button>
            )}
            {isStreaming && (
              <button
                onClick={abort}
                className="rounded bg-red-600 px-3 py-1 text-xs font-medium text-white hover:bg-red-500"
              >
                Stop (Esc)
              </button>
            )}
          </div>
        </div>

        <ChatView
          messages={messages}
          pendingUiRequests={pendingUiRequests}
          respondToUiRequest={respondToUiRequest}
          onSendPrompt={sendPrompt}
          onForkAtEntry={handleForkAtEntry}
          getForkMessages={getForkMessages}
          forkPoints={forkPoints}
          viewMode={viewMode}
        />

        <InputBar onSend={sendPrompt} disabled={!isConnected || isStreaming} />
      </div>
    </div>
  )
}

export default App

import { useState, useRef, useCallback } from 'react'

interface InputBarProps {
  onSend: (text: string, images?: { data: string; mimeType: string }[]) => void
  disabled: boolean
}

function InputBar({ onSend, disabled }: InputBarProps): React.ReactElement {
  const [text, setText] = useState('')
  const [pastedImages, setPastedImages] = useState<{ data: string; mimeType: string }[]>([])
  const textareaRef = useRef<HTMLTextAreaElement>(null)

  const handleSubmit = useCallback((): void => {
    const trimmed = text.trim()
    if (!trimmed && pastedImages.length === 0) return
    if (disabled) return
    onSend(trimmed, pastedImages.length > 0 ? pastedImages : undefined)
    setText('')
    setPastedImages([])
    if (textareaRef.current) {
      textareaRef.current.style.height = 'auto'
    }
  }, [text, pastedImages, disabled, onSend])

  function handleKeyDown(e: React.KeyboardEvent<HTMLTextAreaElement>): void {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      handleSubmit()
    }
  }

  function handleInput(e: React.ChangeEvent<HTMLTextAreaElement>): void {
    setText(e.target.value)
    const el = e.target
    el.style.height = 'auto'
    el.style.height = Math.min(el.scrollHeight, 96) + 'px'
  }

  function handlePaste(e: React.ClipboardEvent): void {
    const items = e.clipboardData.items
    for (const item of items) {
      if (item.type.startsWith('image/')) {
        e.preventDefault()
        const blob = item.getAsFile()
        if (!blob) continue
        const reader = new FileReader()
        reader.onload = () => {
          const result = reader.result as string
          const match = result.match(/^data:(image\/\w+);base64,(.+)$/)
          if (match) {
            setPastedImages((prev) => [...prev, { mimeType: match[1], data: match[2] }])
          }
        }
        reader.readAsDataURL(blob)
      }
    }
  }

  return (
    <div className="border-t border-gray-200 bg-white px-4 py-3">
      {pastedImages.length > 0 && (
        <div className="mb-2 flex gap-2">
          {pastedImages.map((img, i) => (
            <div key={i} className="relative">
              <img
                src={`data:${img.mimeType};base64,${img.data}`}
                alt="pasted"
                className="h-16 rounded border border-gray-200"
              />
              <button
                onClick={() => setPastedImages((prev) => prev.filter((_, j) => j !== i))}
                className="absolute -right-1 -top-1 flex h-4 w-4 items-center justify-center rounded-full bg-red-600 text-[10px] text-white"
              >
                ×
              </button>
            </div>
          ))}
        </div>
      )}
      <div className="flex items-end gap-2">
        <textarea
          ref={textareaRef}
          value={text}
          onChange={handleInput}
          onKeyDown={handleKeyDown}
          onPaste={handlePaste}
          disabled={disabled}
          rows={1}
          placeholder={disabled ? 'Pi not connected...' : 'Type a message... (paste images with Ctrl+V)'}
          className="flex-1 resize-none rounded-lg border border-gray-300 bg-white px-3 py-2 text-sm text-gray-900 placeholder-gray-400 focus:outline-none focus:ring-1 focus:ring-gray-300 disabled:opacity-50"
        />
        <button
          onClick={handleSubmit}
          disabled={disabled || (!text.trim() && pastedImages.length === 0)}
          className="rounded-lg bg-blue-600 px-4 py-2 text-sm font-medium text-white transition-colors hover:bg-blue-500 disabled:opacity-50 disabled:hover:bg-blue-600"
        >
          Send
        </button>
      </div>
    </div>
  )
}

export default InputBar

import { useState, useEffect, useCallback, useRef } from 'react'
import type { ChatMessage, ContentBlock } from '../types/message'
import type {
  AgentSessionEvent,
  MessageUpdateEvent,
  ToolExecutionEndEvent,
  PiImageContent,
  PiUserMessage,
  PiAssistantMessage,
  PiToolResultMessage,
  PiContentBlock,
} from '../types/pi-events'
import type { ForkPoint } from '../types/session'

interface UsePiRpcReturn {
  messages: ChatMessage[]
  isConnected: boolean
  isStreaming: boolean
  sendPrompt: (text: string, images?: { data: string; mimeType: string }[]) => void
  abort: () => void
  pendingUiRequests: Array<{ id: string; method: string; [key: string]: unknown }>
  respondToUiRequest: (requestId: string, response: Record<string, unknown>) => void
  clearMessages: () => void
  loadHistory: () => Promise<void>
  forkPoints: ForkPoint[]
  loadForkPoints: (sessionPath: string) => Promise<void>
  onAgentEnd: (() => void) | null
  setOnAgentEnd: (cb: (() => void) | null) => void
}

export function usePiRpc(): UsePiRpcReturn {
  const [messages, setMessages] = useState<ChatMessage[]>([])
  const [isConnected, setIsConnected] = useState(false)
  const [isStreaming, setIsStreaming] = useState(false)
  const [pendingUiRequests, setPendingUiRequests] = useState<Array<{ id: string; method: string; [key: string]: unknown }>>([])

  const currentAssistantId = useRef<string | null>(null)
  const currentContentBlocks = useRef<Map<number, ContentBlock>>(new Map())
  const toolCallArgsBuffer = useRef<Map<number, string>>(new Map())
  const pendingToolCallArgs = useRef<Map<string, Record<string, unknown>>>(new Map())

  const updateContentBlock = useCallback(
    (contentIndex: number, updater: (block: ContentBlock) => ContentBlock) => {
      const existing = currentContentBlocks.current.get(contentIndex)
      if (existing) {
        currentContentBlocks.current.set(contentIndex, updater(existing))
      }
    },
    [],
  )

  const syncContentBlocksToMessage = useCallback(() => {
    if (!currentAssistantId.current) return
    const blocks = Array.from(currentContentBlocks.current.values())
    const assistantId = currentAssistantId.current
    setMessages((prev) =>
      prev.map((msg) => {
        if (msg.id !== assistantId) return msg
        return { ...msg, blocks: [...blocks] }
      }),
    )
  }, [])

  const finalizeCurrentAssistant = useCallback(() => {
    if (!currentAssistantId.current) return
    syncContentBlocksToMessage()
  }, [syncContentBlocksToMessage])

  const handleEvent = useCallback(
    (event: AgentSessionEvent) => {
      switch (event.type) {
        case 'agent_start':
          setIsStreaming(true)
          break

        case 'agent_end':
          setIsStreaming(false)
          finalizeCurrentAssistant()
          currentAssistantId.current = null
          currentContentBlocks.current.clear()
          toolCallArgsBuffer.current.clear()
          onAgentEndRef.current?.()
          break

        case 'message_start': {
          const msg = event.message
          if (msg.role === 'user') {
            const userMsg = msg as PiUserMessage
            const userContent =
              typeof userMsg.content === 'string'
                ? userMsg.content
                : userMsg.content
                    .filter((c): c is { type: 'text'; text: string } => c.type === 'text')
                    .map((c) => c.text)
                    .join('')

            const userChatMsg: ChatMessage = {
              id: crypto.randomUUID(),
              role: 'user',
              blocks: [{ type: 'text', content: userContent }],
              timestamp: userMsg.timestamp,
            }
            setMessages((prev) => [...prev, userChatMsg])
          } else if (msg.role === 'assistant') {
            const assistantMsg = msg as PiAssistantMessage
            const assistantId = crypto.randomUUID()
            currentAssistantId.current = assistantId
            currentContentBlocks.current.clear()
            toolCallArgsBuffer.current.clear()

            const chatMsg: ChatMessage = {
              id: assistantId,
              role: 'assistant',
              blocks: [],
              timestamp: assistantMsg.timestamp,
            }
            setMessages((prev) => [...prev, chatMsg])
          }
          break
        }

        case 'message_update': {
          const updateEvent = event as MessageUpdateEvent
          const ame = updateEvent.assistantMessageEvent

          if (!currentAssistantId.current) break

          switch (ame.type) {
            case 'text_start':
              currentContentBlocks.current.set(ame.contentIndex, { type: 'text', content: '' })
              break

            case 'text_delta':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: block.content + ame.delta }
                }
                return block
              })
              break

            case 'text_end':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: ame.content }
                }
                return block
              })
              break

            case 'thinking_start':
              currentContentBlocks.current.set(ame.contentIndex, { type: 'text', content: '💭 ' })
              break

            case 'thinking_delta':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: block.content + ame.delta }
                }
                return block
              })
              break

            case 'thinking_end':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: '💭 ' + ame.content }
                }
                return block
              })
              break

            case 'toolcall_start':
              currentContentBlocks.current.set(ame.contentIndex, {
                type: 'tool_call',
                toolName: '',
                args: {},
                status: 'running',
              })
              toolCallArgsBuffer.current.set(ame.contentIndex, '')
              break

            case 'toolcall_delta': {
              const existing = toolCallArgsBuffer.current.get(ame.contentIndex) ?? ''
              toolCallArgsBuffer.current.set(ame.contentIndex, existing + ame.delta)
              break
            }

            case 'toolcall_end': {
              const argsStr = toolCallArgsBuffer.current.get(ame.contentIndex) ?? '{}'
              let parsedArgs: Record<string, unknown>
              try {
                parsedArgs = JSON.parse(argsStr)
              } catch {
                parsedArgs = { _raw: argsStr }
              }
              currentContentBlocks.current.set(ame.contentIndex, {
                type: 'tool_call',
                toolName: ame.toolCall.name,
                args: parsedArgs,
                status: 'running',
              })
              pendingToolCallArgs.current.set(ame.toolCall.id, parsedArgs)
              toolCallArgsBuffer.current.delete(ame.contentIndex)
              syncContentBlocksToMessage()
              break
            }

            case 'done':
            case 'error':
              break
          }

          if (ame.type !== 'toolcall_end') {
            syncContentBlocksToMessage()
          }
          break
        }

        case 'message_end': {
          const msg = event.message
          if (msg.role === 'toolResult') {
            const toolResultMsg = msg as PiToolResultMessage
            const extraBlocks: ContentBlock[] = []

            for (const content of toolResultMsg.content) {
              if (content.type === 'text') {
                extraBlocks.push({ type: 'text', content: content.text })
              } else if (content.type === 'image') {
                const img = content as PiImageContent
                extraBlocks.push({
                  type: 'image',
                  src: `data:${img.mimeType};base64,${img.data}`,
                  alt: 'Screenshot',
                })
              }
            }

            if (extraBlocks.length > 0 && currentAssistantId.current) {
              setMessages((prev) =>
                prev.map((m) => {
                  if (m.id !== currentAssistantId.current) return m
                  return { ...m, blocks: [...m.blocks, ...extraBlocks] }
                }),
              )
            }
          }
          break
        }

        case 'tool_execution_start':
          setMessages((prev) =>
            prev.map((msg) => {
              if (msg.id !== currentAssistantId.current) return msg
              return {
                ...msg,
                blocks: msg.blocks.map((block) => {
                  if (
                    block.type === 'tool_call' &&
                    block.toolName === event.toolName &&
                    block.status === 'pending'
                  ) {
                    return { ...block, status: 'running' as const }
                  }
                  return block
                }),
              }
            }),
          )
          break

        case 'tool_execution_end': {
          const toolEvent = event as ToolExecutionEndEvent
          const toolArgs = pendingToolCallArgs.current.get(toolEvent.toolCallId)
          pendingToolCallArgs.current.delete(toolEvent.toolCallId)

          const extraBlocks: ContentBlock[] = []

          const hasImageContent = toolEvent.result?.content?.some(
            (c: Record<string, unknown>) => c.type === 'image'
          )

          if (hasImageContent) {
            for (const c of toolEvent.result.content as Array<Record<string, unknown>>) {
              if (c.type === 'text' && typeof c.text === 'string') {
                extraBlocks.push({ type: 'text', content: c.text })
              } else if (c.type === 'image') {
                const img = c as unknown as PiImageContent
                extraBlocks.push({
                  type: 'image',
                  src: `data:${img.mimeType};base64,${img.data}`,
                  alt: `Result from ${toolEvent.toolName}`,
                })
              }
            }
          }

          if (
            toolEvent.toolName === 'write' &&
            toolArgs &&
            typeof toolArgs.path === 'string' &&
            toolArgs.path.endsWith('.html') &&
            typeof toolArgs.content === 'string'
          ) {
            extraBlocks.push({
              type: 'html',
              content: toolArgs.content,
              title: toolArgs.path.split('/').pop(),
            })
          }

          if (extraBlocks.length > 0) {
            setMessages((prev) =>
              prev.map((msg) => {
                if (msg.id !== currentAssistantId.current) return msg
                return {
                  ...msg,
                  blocks: [
                    ...msg.blocks.map((block) => {
                      if (block.type === 'tool_call' && block.status === 'running') {
                        return { ...block, status: 'completed' as const }
                      }
                      return block
                    }),
                    ...extraBlocks,
                  ],
                }
              }),
            )
          } else {
            setMessages((prev) =>
              prev.map((msg) => {
                if (msg.id !== currentAssistantId.current) return msg
                return {
                  ...msg,
                  blocks: msg.blocks.map((block) => {
                    if (block.type === 'tool_call' && block.status === 'running') {
                      return { ...block, status: 'completed' as const }
                    }
                    return block
                  }),
                }
              }),
            )
          }
          break
        }

        default:
          break
      }
    },
    [updateContentBlock, syncContentBlocksToMessage, finalizeCurrentAssistant],
  )

  useEffect(() => {
    const cleanup = window.api.onStateChanged((state) => {
      setIsConnected(state.connected)
    })

    window.api.getState().then((state) => {
      setIsConnected(state.connected)
    })

    return cleanup
  }, [])

  useEffect(() => {
    const cleanup = window.api.onEvent((rawEvent) => {
      handleEvent(rawEvent as AgentSessionEvent)
    })
    return cleanup
  }, [handleEvent])

  useEffect(() => {
    const cleanup = window.api.onExtensionUiRequest((data) => {
      const req = data as { id: string; method: string; [key: string]: unknown }
      if (req.method === 'notify') {
        return
      }
      if (req.method === 'setStatus' || req.method === 'setWidget' || req.method === 'setTitle' || req.method === 'set_editor_text') {
        return
      }
      setPendingUiRequests(prev => [...prev, req])
    })
    return cleanup
  }, [])

  const respondToUiRequest = useCallback((requestId: string, response: Record<string, unknown>) => {
    window.api.sendExtensionUIResponse({ type: 'extension_ui_response', id: requestId, ...response })
    setPendingUiRequests(prev => prev.filter(r => r.id !== requestId))
  }, [])

  const sendPrompt = useCallback(
    (text: string, images?: { data: string; mimeType: string }[]) => {
      const command: Record<string, unknown> = {
        type: 'prompt',
        message: text,
        id: crypto.randomUUID(),
      }
      if (images && images.length > 0) {
        command.images = images.map((img) => ({
          type: 'image' as const,
          data: img.data,
          mimeType: img.mimeType,
        }))
      }
      window.api.sendCommand(command)
    },
    [],
  )

  const abort = useCallback(() => {
    window.api.sendCommand({ type: 'abort' })
  }, [])

  const clearMessages = useCallback(() => {
    setMessages([])
    setForkPoints([])
    currentAssistantId.current = null
    currentContentBlocks.current.clear()
    toolCallArgsBuffer.current.clear()
    pendingToolCallArgs.current.clear()
  }, [])

  const [forkPoints, setForkPoints] = useState<ForkPoint[]>([])
  const onAgentEndRef = useRef<(() => void) | null>(null)

  const setOnAgentEnd = useCallback((cb: (() => void) | null) => {
    onAgentEndRef.current = cb
  }, [])

  const loadForkPoints = useCallback(async (sessionPath: string) => {
    type ExtendedApiWithForkPoints = typeof window.api & { getForkPoints: (path: string) => Promise<ForkPoint[]> }
    const apiWithFp = window.api as ExtendedApiWithForkPoints
    try {
      const points = await apiWithFp.getForkPoints(sessionPath)
      setForkPoints(points)
    } catch {
      setForkPoints([])
    }
  }, [])

  const loadHistory = useCallback(async () => {
    type ExtendedApiWithMessages = typeof window.api & { getMessages: () => Promise<unknown[]> }
    const api = window.api as ExtendedApiWithMessages

    let piMessages: unknown[]
    try {
      piMessages = await api.getMessages()
    } catch {
      return
    }

    if (!Array.isArray(piMessages) || piMessages.length === 0) {
      clearMessages()
      return
    }

    const chatMessages: ChatMessage[] = []

    for (const raw of piMessages) {
      const msg = raw as Record<string, unknown>
      const piEntryId = typeof msg.id === 'string' ? msg.id : undefined
      if (msg.role === 'user') {
        const content = typeof msg.content === 'string'
          ? msg.content
          : Array.isArray(msg.content)
            ? (msg.content as PiContentBlock[])
                .filter((c): c is { type: 'text'; text: string } => c.type === 'text')
                .map((c) => c.text)
                .join('')
            : ''
        chatMessages.push({
          id: crypto.randomUUID(),
          role: 'user',
          blocks: [{ type: 'text', content }],
          timestamp: typeof msg.timestamp === 'number' ? msg.timestamp : Date.now(),
          piEntryId,
        })
      } else if (msg.role === 'assistant') {
        const blocks: ContentBlock[] = []
        const content = msg.content as PiContentBlock[]
        if (Array.isArray(content)) {
          for (const c of content) {
            if (c.type === 'text') {
              blocks.push({ type: 'text', content: c.text })
            } else if (c.type === 'thinking') {
              blocks.push({ type: 'text', content: '\u{1F4AD} ' + c.thinking })
            } else if (c.type === 'toolCall') {
              blocks.push({
                type: 'tool_call',
                toolName: c.name,
                args: c.arguments,
                status: 'completed',
              })
            }
          }
        }
        chatMessages.push({
          id: crypto.randomUUID(),
          role: 'assistant',
          blocks,
          timestamp: typeof msg.timestamp === 'number' ? msg.timestamp : Date.now(),
          piEntryId,
        })
      } else if (msg.role === 'toolResult') {
        const lastAssistant = chatMessages.findLast((m) => m.role === 'assistant')
        if (lastAssistant) {
          const content = msg.content as PiContentBlock[]
          if (Array.isArray(content)) {
            for (const c of content) {
              if (c.type === 'text') {
                lastAssistant.blocks.push({ type: 'text', content: c.text })
              } else if (c.type === 'image') {
                const img = c as PiImageContent
                lastAssistant.blocks.push({
                  type: 'image',
                  src: `data:${img.mimeType};base64,${img.data}`,
                  alt: `Result from ${msg.toolName as string}`,
                })
              }
            }
          }
        }
      }
    }

    clearMessages()
    setMessages(chatMessages)
  }, [clearMessages])

  return { messages, isConnected, isStreaming, sendPrompt, abort, pendingUiRequests, respondToUiRequest, clearMessages, loadHistory, forkPoints, loadForkPoints, onAgentEnd: onAgentEndRef.current, setOnAgentEnd }
}

export interface ChatMessage {
  id: string;
  role: 'user' | 'assistant' | 'system';
  blocks: ContentBlock[];
  timestamp: number;
  piEntryId?: string;
}

export type ContentBlock =
  | TextBlock
  | ImageBlock
  | HtmlBlock
  | ToolCallBlock
  | ToolResultBlock
  | ActionBlock;

export interface TextBlock {
  type: 'text';
  content: string;
}

export interface ImageBlock {
  type: 'image';
  src: string;
  alt?: string;
  width?: number;
  height?: number;
  annotations?: Annotation[];
}

export interface HtmlBlock {
  type: 'html';
  content: string;
  title?: string;
}

export interface ToolCallBlock {
  type: 'tool_call';
  toolName: string;
  args: Record<string, unknown>;
  status: 'pending' | 'running' | 'completed' | 'error';
}

export interface ToolResultBlock {
  type: 'tool_result';
  toolCallId: string;
  content: ContentBlock[];
}

export interface ActionBlock {
  type: 'action';
  actionType: 'select' | 'confirm' | 'input';
  label: string;
  options?: { id: string; label: string; description?: string }[];
}

export interface Annotation {
  id: string;
  type: 'rect' | 'circle' | 'arrow' | 'text';
  coords: number[];
  label?: string;
  color?: string;
}

// === Pi RPC Event Types ===
// These are the events emitted on stdout by `pi --mode rpc`

// === Non-event stdout objects ===

export interface SessionHeader {
  type: 'session'
  version: number
  id: string
  timestamp: string
  cwd: string
}

export interface RpcResponse {
  id?: string
  type: 'response'
  command: string
  success: boolean
  data?: unknown
  error?: string
}

export interface ExtensionUIRequest {
  type: 'extension_ui_request'
  id: string
  method: 'select' | 'confirm' | 'input' | 'editor' | 'notify' | 'setStatus' | 'setWidget' | 'setTitle' | 'set_editor_text'
  [key: string]: unknown
}

export interface ExtensionUIResponse {
  type: 'extension_ui_response'
  id: string
  value?: string
  confirmed?: boolean
  cancelled?: true
}

export interface ExtensionError {
  type: 'extension_error'
  extensionPath: string
  event: string
  error: string
}

// === Agent Lifecycle Events ===

export interface AgentStartEvent {
  type: 'agent_start'
}

export interface AgentEndEvent {
  type: 'agent_end'
  messages: unknown[]
  willRetry: boolean
}

// === Turn Events ===

export interface TurnStartEvent {
  type: 'turn_start'
}

export interface TurnEndEvent {
  type: 'turn_end'
  message: unknown
  toolResults: unknown[]
}

// === Message Events ===

export interface MessageStartEvent {
  type: 'message_start'
  message: PiMessage
}

export interface MessageUpdateEvent {
  type: 'message_update'
  message: PiAssistantMessage
  assistantMessageEvent: AssistantMessageEvent
}

export interface MessageEndEvent {
  type: 'message_end'
  message: PiMessage
}

// === Assistant Message Streaming Events ===

export type AssistantMessageEvent =
  | { type: 'start'; partial: PiAssistantMessage }
  | { type: 'text_start'; contentIndex: number; partial: PiAssistantMessage }
  | { type: 'text_delta'; contentIndex: number; delta: string; partial: PiAssistantMessage }
  | { type: 'text_end'; contentIndex: number; content: string; partial: PiAssistantMessage }
  | { type: 'thinking_start'; contentIndex: number; partial: PiAssistantMessage }
  | { type: 'thinking_delta'; contentIndex: number; delta: string; partial: PiAssistantMessage }
  | { type: 'thinking_end'; contentIndex: number; content: string; partial: PiAssistantMessage }
  | { type: 'toolcall_start'; contentIndex: number; partial: PiAssistantMessage }
  | { type: 'toolcall_delta'; contentIndex: number; delta: string; partial: PiAssistantMessage }
  | { type: 'toolcall_end'; contentIndex: number; toolCall: PiToolCall; partial: PiAssistantMessage }
  | { type: 'done'; reason: 'stop' | 'length' | 'toolUse'; message: PiAssistantMessage }
  | { type: 'error'; reason: 'aborted' | 'error'; error: PiAssistantMessage }

// === Tool Execution Events ===

export interface ToolExecutionStartEvent {
  type: 'tool_execution_start'
  toolCallId: string
  toolName: string
  args: Record<string, unknown>
}

export interface ToolExecutionUpdateEvent {
  type: 'tool_execution_update'
  toolCallId: string
  toolName: string
  args: Record<string, unknown>
  partialResult: { content: PiContentBlock[]; details: unknown }
}

export interface ToolExecutionEndEvent {
  type: 'tool_execution_end'
  toolCallId: string
  toolName: string
  result: { content: PiContentBlock[]; details: unknown }
  isError: boolean
}

// === Session Events ===

export interface QueueUpdateEvent {
  type: 'queue_update'
  steering: string[]
  followUp: string[]
}

export interface CompactionStartEvent {
  type: 'compaction_start'
  reason: 'manual' | 'threshold' | 'overflow'
}

export interface CompactionEndEvent {
  type: 'compaction_end'
  reason: 'manual' | 'threshold' | 'overflow'
  result: unknown
  aborted: boolean
  willRetry: boolean
  errorMessage?: string
}

export interface SessionInfoChangedEvent {
  type: 'session_info_changed'
  name: string
}

export interface ThinkingLevelChangedEvent {
  type: 'thinking_level_changed'
  level: string
}

export interface AutoRetryStartEvent {
  type: 'auto_retry_start'
  attempt: number
  maxAttempts: number
  delayMs: number
  errorMessage: string
}

export interface AutoRetryEndEvent {
  type: 'auto_retry_end'
  success: boolean
  attempt: number
  finalError?: string
}

// === Union of ALL AgentSessionEvents ===

export type AgentSessionEvent =
  | AgentStartEvent
  | AgentEndEvent
  | TurnStartEvent
  | TurnEndEvent
  | MessageStartEvent
  | MessageUpdateEvent
  | MessageEndEvent
  | ToolExecutionStartEvent
  | ToolExecutionUpdateEvent
  | ToolExecutionEndEvent
  | QueueUpdateEvent
  | CompactionStartEvent
  | CompactionEndEvent
  | SessionInfoChangedEvent
  | ThinkingLevelChangedEvent
  | AutoRetryStartEvent
  | AutoRetryEndEvent
  | ExtensionError

// === Pi Content Block Types ===

export interface PiTextContent {
  type: 'text'
  text: string
}

export interface PiImageContent {
  type: 'image'
  data: string // base64
  mimeType: string
}

export interface PiThinkingContent {
  type: 'thinking'
  thinking: string
  thinkingSignature: string
  redacted: boolean
}

export interface PiToolCall {
  type: 'toolCall'
  id: string
  name: string
  arguments: Record<string, unknown>
}

export type PiContentBlock = PiTextContent | PiImageContent | PiThinkingContent | PiToolCall

// === Pi Message Types ===

export interface PiUserMessage {
  role: 'user'
  content: string | PiContentBlock[]
  timestamp: number
}

export interface PiAssistantMessage {
  role: 'assistant'
  content: PiContentBlock[]
  api: string
  provider: string
  model: string
  responseModel: string
  responseId: string
  usage: {
    input: number
    output: number
    cacheRead: number
    cacheWrite: number
    totalTokens: number
    cost: { input: number; output: number; cacheRead: number; cacheWrite: number; total: number }
  }
  stopReason: 'stop' | 'length' | 'toolUse' | 'error' | 'aborted'
  timestamp: number
}

export interface PiToolResultMessage {
  role: 'toolResult'
  toolCallId: string
  toolName: string
  content: PiContentBlock[]
  details: unknown
  isError: boolean
  timestamp: number
}

export type PiMessage = PiUserMessage | PiAssistantMessage | PiToolResultMessage

import { useState, useEffect, useCallback, useRef } from 'react'
import type { ChatMessage, ContentBlock } from '../types/message'
import type {
  AgentSessionEvent,
  MessageUpdateEvent,
  ToolExecutionEndEvent,
  PiImageContent,
  PiUserMessage,
  PiAssistantMessage,
  PiToolResultMessage,
  PiContentBlock,
} from '../types/pi-events'
import type { ForkPoint } from '../types/session'

export interface TokenUsage {
  inputTokens: number
  outputTokens: number
  cacheReadTokens: number
  cacheWriteTokens: number
  totalTokens: number
  totalCost: number
  contextWindowSize: number
}

function inferContextWindow(model: string): number {
  if (!model) return 200000
  const m = model.toLowerCase()
  if (m.includes('gpt-4o') || m.includes('gpt-4-turbo')) return 128000
  if (m.includes('claude')) return 200000
  return 200000
}

interface UsePiRpcReturn {
  messages: ChatMessage[]
  isConnected: boolean
  isStreaming: boolean
  sendPrompt: (text: string, images?: { data: string; mimeType: string }[]) => void
  abort: () => void
  pendingUiRequests: Array<{ id: string; method: string; [key: string]: unknown }>
  respondToUiRequest: (requestId: string, response: Record<string, unknown>) => void
  clearMessages: () => void
  loadHistory: () => Promise<void>
  forkPoints: ForkPoint[]
  loadForkPoints: (sessionPath: string) => Promise<void>
  onAgentEnd: (() => void) | null
  setOnAgentEnd: (cb: (() => void) | null) => void
  tokenUsage: TokenUsage
}

export function usePiRpc(): UsePiRpcReturn {
  const [messages, setMessages] = useState<ChatMessage[]>([])
  const [isConnected, setIsConnected] = useState(false)
  const [isStreaming, setIsStreaming] = useState(false)
  const [pendingUiRequests, setPendingUiRequests] = useState<Array<{ id: string; method: string; [key: string]: unknown }>>([])
  const [tokenUsage, setTokenUsage] = useState<TokenUsage>({
    inputTokens: 0,
    outputTokens: 0,
    cacheReadTokens: 0,
    cacheWriteTokens: 0,
    totalTokens: 0,
    totalCost: 0,
    contextWindowSize: 200000,
  })

  const currentAssistantId = useRef<string | null>(null)
  const currentContentBlocks = useRef<Map<number, ContentBlock>>(new Map())
  const toolCallArgsBuffer = useRef<Map<number, string>>(new Map())
  const pendingToolCallArgs = useRef<Map<string, Record<string, unknown>>>(new Map())

  const updateContentBlock = useCallback(
    (contentIndex: number, updater: (block: ContentBlock) => ContentBlock) => {
      const existing = currentContentBlocks.current.get(contentIndex)
      if (existing) {
        currentContentBlocks.current.set(contentIndex, updater(existing))
      }
    },
    [],
  )

  const syncContentBlocksToMessage = useCallback(() => {
    if (!currentAssistantId.current) return
    const blocks = Array.from(currentContentBlocks.current.values())
    const assistantId = currentAssistantId.current
    setMessages((prev) =>
      prev.map((msg) => {
        if (msg.id !== assistantId) return msg
        return { ...msg, blocks: [...blocks] }
      }),
    )
  }, [])

  const finalizeCurrentAssistant = useCallback(() => {
    if (!currentAssistantId.current) return
    syncContentBlocksToMessage()
  }, [syncContentBlocksToMessage])

  const handleEvent = useCallback(
    (event: AgentSessionEvent) => {
      switch (event.type) {
        case 'agent_start':
          setIsStreaming(true)
          break

        case 'agent_end':
          setIsStreaming(false)
          finalizeCurrentAssistant()
          currentAssistantId.current = null
          currentContentBlocks.current.clear()
          toolCallArgsBuffer.current.clear()
          onAgentEndRef.current?.()
          break

        case 'message_start': {
          const msg = event.message
          if (msg.role === 'user') {
            const userMsg = msg as PiUserMessage
            const userContent =
              typeof userMsg.content === 'string'
                ? userMsg.content
                : userMsg.content
                    .filter((c): c is { type: 'text'; text: string } => c.type === 'text')
                    .map((c) => c.text)
                    .join('')

            const userChatMsg: ChatMessage = {
              id: crypto.randomUUID(),
              role: 'user',
              blocks: [{ type: 'text', content: userContent }],
              timestamp: userMsg.timestamp,
            }
            setMessages((prev) => [...prev, userChatMsg])
          } else if (msg.role === 'assistant') {
            const assistantMsg = msg as PiAssistantMessage
            const assistantId = crypto.randomUUID()
            currentAssistantId.current = assistantId
            currentContentBlocks.current.clear()
            toolCallArgsBuffer.current.clear()

            const chatMsg: ChatMessage = {
              id: assistantId,
              role: 'assistant',
              blocks: [],
              timestamp: assistantMsg.timestamp,
            }
            setMessages((prev) => [...prev, chatMsg])
          }
          break
        }

        case 'message_update': {
          const updateEvent = event as MessageUpdateEvent
          const ame = updateEvent.assistantMessageEvent

          if (!currentAssistantId.current) break

          switch (ame.type) {
            case 'text_start':
              currentContentBlocks.current.set(ame.contentIndex, { type: 'text', content: '' })
              break

            case 'text_delta':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: block.content + ame.delta }
                }
                return block
              })
              break

            case 'text_end':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: ame.content }
                }
                return block
              })
              break

            case 'thinking_start':
              currentContentBlocks.current.set(ame.contentIndex, { type: 'text', content: '💭 ' })
              break

            case 'thinking_delta':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: block.content + ame.delta }
                }
                return block
              })
              break

            case 'thinking_end':
              updateContentBlock(ame.contentIndex, (block) => {
                if (block.type === 'text') {
                  return { ...block, content: '💭 ' + ame.content }
                }
                return block
              })
              break

            case 'toolcall_start':
              currentContentBlocks.current.set(ame.contentIndex, {
                type: 'tool_call',
                toolName: '',
                args: {},
                status: 'running',
              })
              toolCallArgsBuffer.current.set(ame.contentIndex, '')
              break

            case 'toolcall_delta': {
              const existing = toolCallArgsBuffer.current.get(ame.contentIndex) ?? ''
              toolCallArgsBuffer.current.set(ame.contentIndex, existing + ame.delta)
              break
            }

            case 'toolcall_end': {
              const argsStr = toolCallArgsBuffer.current.get(ame.contentIndex) ?? '{}'
              let parsedArgs: Record<string, unknown>
              try {
                parsedArgs = JSON.parse(argsStr)
              } catch {
                parsedArgs = { _raw: argsStr }
              }
              currentContentBlocks.current.set(ame.contentIndex, {
                type: 'tool_call',
                toolName: ame.toolCall.name,
                args: parsedArgs,
                status: 'running',
              })
              pendingToolCallArgs.current.set(ame.toolCall.id, parsedArgs)
              toolCallArgsBuffer.current.delete(ame.contentIndex)
              syncContentBlocksToMessage()
              break
            }

            case 'done': {
              const msg = ame.message
              if (msg.usage) {
                setTokenUsage({
                  inputTokens: msg.usage.input,
                  outputTokens: msg.usage.output,
                  cacheReadTokens: msg.usage.cacheRead,
                  cacheWriteTokens: msg.usage.cacheWrite,
                  totalTokens: msg.usage.input + msg.usage.output,
                  totalCost: msg.usage.cost.total,
                  contextWindowSize: inferContextWindow(msg.responseModel),
                })
              }
              break
            }
            case 'error':
              break
          }

          if (ame.type !== 'toolcall_end') {
            syncContentBlocksToMessage()
          }
          break
        }

        case 'message_end': {
          const msg = event.message
          if (msg.role === 'toolResult') {
            const toolResultMsg = msg as PiToolResultMessage
            const extraBlocks: ContentBlock[] = []

            for (const content of toolResultMsg.content) {
              if (content.type === 'text') {
                extraBlocks.push({ type: 'text', content: content.text })
              } else if (content.type === 'image') {
                const img = content as PiImageContent
                extraBlocks.push({
                  type: 'image',
                  src: `data:${img.mimeType};base64,${img.data}`,
                  alt: 'Screenshot',
                })
              }
            }

            if (extraBlocks.length > 0 && currentAssistantId.current) {
              setMessages((prev) =>
                prev.map((m) => {
                  if (m.id !== currentAssistantId.current) return m
                  return { ...m, blocks: [...m.blocks, ...extraBlocks] }
                }),
              )
            }
          }
          if (msg.role === 'assistant') {
            const assistantMsg = msg as PiAssistantMessage
            if (assistantMsg.usage) {
              setTokenUsage({
                inputTokens: assistantMsg.usage.input,
                outputTokens: assistantMsg.usage.output,
                cacheReadTokens: assistantMsg.usage.cacheRead,
                cacheWriteTokens: assistantMsg.usage.cacheWrite,
                totalTokens: assistantMsg.usage.input + assistantMsg.usage.output,
                totalCost: assistantMsg.usage.cost.total,
                contextWindowSize: inferContextWindow(assistantMsg.responseModel),
              })
            }
          }
          break
        }

        case 'tool_execution_start':
          setMessages((prev) =>
            prev.map((msg) => {
              if (msg.id !== currentAssistantId.current) return msg
              return {
                ...msg,
                blocks: msg.blocks.map((block) => {
                  if (
                    block.type === 'tool_call' &&
                    block.toolName === event.toolName &&
                    block.status === 'pending'
                  ) {
                    return { ...block, status: 'running' as const }
                  }
                  return block
                }),
              }
            }),
          )
          break

        case 'tool_execution_end': {
          const toolEvent = event as ToolExecutionEndEvent
          const toolArgs = pendingToolCallArgs.current.get(toolEvent.toolCallId)
          pendingToolCallArgs.current.delete(toolEvent.toolCallId)

          const extraBlocks: ContentBlock[] = []

          const hasImageContent = toolEvent.result?.content?.some(
            (c: Record<string, unknown>) => c.type === 'image'
          )

          if (hasImageContent) {
            for (const c of toolEvent.result.content as Array<Record<string, unknown>>) {
              if (c.type === 'text' && typeof c.text === 'string') {
                extraBlocks.push({ type: 'text', content: c.text })
              } else if (c.type === 'image') {
                const img = c as unknown as PiImageContent
                extraBlocks.push({
                  type: 'image',
                  src: `data:${img.mimeType};base64,${img.data}`,
                  alt: `Result from ${toolEvent.toolName}`,
                })
              }
            }
          }

          if (
            toolEvent.toolName === 'write' &&
            toolArgs &&
            typeof toolArgs.path === 'string' &&
            toolArgs.path.endsWith('.html') &&
            typeof toolArgs.content === 'string'
          ) {
            extraBlocks.push({
              type: 'html',
              content: toolArgs.content,
              title: toolArgs.path.split('/').pop(),
            })
          }

          if (extraBlocks.length > 0) {
            setMessages((prev) =>
              prev.map((msg) => {
                if (msg.id !== currentAssistantId.current) return msg
                return {
                  ...msg,
                  blocks: [
                    ...msg.blocks.map((block) => {
                      if (block.type === 'tool_call' && block.status === 'running') {
                        return { ...block, status: 'completed' as const }
                      }
                      return block
                    }),
                    ...extraBlocks,
                  ],
                }
              }),
            )
          } else {
            setMessages((prev) =>
              prev.map((msg) => {
                if (msg.id !== currentAssistantId.current) return msg
                return {
                  ...msg,
                  blocks: msg.blocks.map((block) => {
                    if (block.type === 'tool_call' && block.status === 'running') {
                      return { ...block, status: 'completed' as const }
                    }
                    return block
                  }),
                }
              }),
            )
          }
          break
        }

        default:
          break
      }
    },
    [updateContentBlock, syncContentBlocksToMessage, finalizeCurrentAssistant],
  )

  useEffect(() => {
    const cleanup = window.api.onStateChanged((state) => {
      setIsConnected(state.connected)
    })

    window.api.getState().then((state) => {
      setIsConnected(state.connected)
    })

    return cleanup
  }, [])

  useEffect(() => {
    const cleanup = window.api.onEvent((rawEvent) => {
      handleEvent(rawEvent as AgentSessionEvent)
    })
    return cleanup
  }, [handleEvent])

  useEffect(() => {
    const cleanup = window.api.onExtensionUiRequest((data) => {
      const req = data as { id: string; method: string; [key: string]: unknown }
      if (req.method === 'notify') {
        return
      }
      if (req.method === 'setStatus' || req.method === 'setWidget' || req.method === 'setTitle' || req.method === 'set_editor_text') {
        return
      }
      setPendingUiRequests(prev => [...prev, req])
    })
    return cleanup
  }, [])

  const respondToUiRequest = useCallback((requestId: string, response: Record<string, unknown>) => {
    window.api.sendExtensionUIResponse({ type: 'extension_ui_response', id: requestId, ...response })
    setPendingUiRequests(prev => prev.filter(r => r.id !== requestId))
  }, [])

  const sendPrompt = useCallback(
    (text: string, images?: { data: string; mimeType: string }[]) => {
      const command: Record<string, unknown> = {
        type: 'prompt',
        message: text,
        id: crypto.randomUUID(),
      }
      if (images && images.length > 0) {
        command.images = images.map((img) => ({
          type: 'image' as const,
          data: img.data,
          mimeType: img.mimeType,
        }))
      }
      window.api.sendCommand(command)
    },
    [],
  )

  const abort = useCallback(() => {
    window.api.sendCommand({ type: 'abort' })
  }, [])

  const clearMessages = useCallback(() => {
    setMessages([])
    setForkPoints([])
    setTokenUsage({
      inputTokens: 0,
      outputTokens: 0,
      cacheReadTokens: 0,
      cacheWriteTokens: 0,
      totalTokens: 0,
      totalCost: 0,
      contextWindowSize: 200000,
    })
    currentAssistantId.current = null
    currentContentBlocks.current.clear()
    toolCallArgsBuffer.current.clear()
    pendingToolCallArgs.current.clear()
  }, [])

  const [forkPoints, setForkPoints] = useState<ForkPoint[]>([])
  const onAgentEndRef = useRef<(() => void) | null>(null)

  const setOnAgentEnd = useCallback((cb: (() => void) | null) => {
    onAgentEndRef.current = cb
  }, [])

  const loadForkPoints = useCallback(async (sessionPath: string) => {
    type ExtendedApiWithForkPoints = typeof window.api & { getForkPoints: (path: string) => Promise<ForkPoint[]> }
    const apiWithFp = window.api as ExtendedApiWithForkPoints
    try {
      const points = await apiWithFp.getForkPoints(sessionPath)
      setForkPoints(points)
    } catch {
      setForkPoints([])
    }
  }, [])

  const loadHistory = useCallback(async () => {
    type ExtendedApiWithMessages = typeof window.api & { getMessages: () => Promise<unknown[]> }
    const api = window.api as ExtendedApiWithMessages

    let piMessages: unknown[]
    try {
      piMessages = await api.getMessages()
    } catch {
      return
    }

    if (!Array.isArray(piMessages) || piMessages.length === 0) {
      clearMessages()
      return
    }

    const chatMessages: ChatMessage[] = []

    for (const raw of piMessages) {
      const msg = raw as Record<string, unknown>
      const piEntryId = typeof msg.id === 'string' ? msg.id : undefined
      if (msg.role === 'user') {
        const content = typeof msg.content === 'string'
          ? msg.content
          : Array.isArray(msg.content)
            ? (msg.content as PiContentBlock[])
                .filter((c): c is { type: 'text'; text: string } => c.type === 'text')
                .map((c) => c.text)
                .join('')
            : ''
        chatMessages.push({
          id: crypto.randomUUID(),
          role: 'user',
          blocks: [{ type: 'text', content }],
          timestamp: typeof msg.timestamp === 'number' ? msg.timestamp : Date.now(),
          piEntryId,
        })
      } else if (msg.role === 'assistant') {
        const blocks: ContentBlock[] = []
        const content = msg.content as PiContentBlock[]
        if (Array.isArray(content)) {
          for (const c of content) {
            if (c.type === 'text') {
              blocks.push({ type: 'text', content: c.text })
            } else if (c.type === 'thinking') {
              blocks.push({ type: 'text', content: '\u{1F4AD} ' + c.thinking })
            } else if (c.type === 'toolCall') {
              blocks.push({
                type: 'tool_call',
                toolName: c.name,
                args: c.arguments,
                status: 'completed',
              })
            }
          }
        }
        chatMessages.push({
          id: crypto.randomUUID(),
          role: 'assistant',
          blocks,
          timestamp: typeof msg.timestamp === 'number' ? msg.timestamp : Date.now(),
          piEntryId,
        })
      } else if (msg.role === 'toolResult') {
        const lastAssistant = chatMessages.findLast((m) => m.role === 'assistant')
        if (lastAssistant) {
          const content = msg.content as PiContentBlock[]
          if (Array.isArray(content)) {
            for (const c of content) {
              if (c.type === 'text') {
                lastAssistant.blocks.push({ type: 'text', content: c.text })
              } else if (c.type === 'image') {
                const img = c as PiImageContent
                lastAssistant.blocks.push({
                  type: 'image',
                  src: `data:${img.mimeType};base64,${img.data}`,
                  alt: `Result from ${msg.toolName as string}`,
                })
              }
            }
          }
        }
      }
    }

    // Extract token usage from last assistant message in history
    for (let i = piMessages.length - 1; i >= 0; i--) {
      const msg = piMessages[i] as Record<string, unknown>
      if (msg.role === 'assistant') {
        const usage = msg.usage as { input: number; output: number; cacheRead: number; cacheWrite: number; totalTokens: number; cost: { input: number; output: number; cacheRead: number; cacheWrite: number; total: number } } | undefined
        const responseModel = typeof msg.responseModel === 'string' ? msg.responseModel : ''
        if (usage) {
          setTokenUsage({
            inputTokens: usage.input,
            outputTokens: usage.output,
            cacheReadTokens: usage.cacheRead,
            cacheWriteTokens: usage.cacheWrite,
            totalTokens: usage.input + usage.output,
            totalCost: usage.cost.total,
            contextWindowSize: inferContextWindow(responseModel),
          })
        }
        break
      }
    }

    clearMessages()
    setMessages(chatMessages)
  }, [clearMessages])

  return { messages, isConnected, isStreaming, sendPrompt, abort, pendingUiRequests, respondToUiRequest, clearMessages, loadHistory, forkPoints, loadForkPoints, onAgentEnd: onAgentEndRef.current, setOnAgentEnd, tokenUsage }
}

import { useState, useCallback, useEffect } from 'react'
import type { SessionListResult, SessionInfo, ForkableMessage, ForkPoint, SessionIpcApi } from '../types/session'

type ExtendedApi = typeof window.api & SessionIpcApi
const api = window.api as ExtendedApi

interface UseSessionManagerReturn {
  sessions: SessionListResult | null
  currentSession: SessionInfo | null
  forkMessages: ForkableMessage[]
  loadSessions: () => Promise<void>
  forkAtEntry: (entryId: string, name: string) => Promise<void>
  switchSession: (sessionPath: string) => Promise<{ success: boolean; error?: string }>
  newSession: (name: string, parentSessionPath?: string) => Promise<boolean>
  renameSession: (name: string) => Promise<void>
  deleteSession: (sessionPath: string) => Promise<boolean>
  getForkPoints: (sessionPath: string) => Promise<ForkPoint[]>
  refresh: () => Promise<void>
  getForkMessages: () => Promise<ForkableMessage[]>
  clearSession: () => Promise<boolean>
}

export function useSessionManager(isConnected: boolean): UseSessionManagerReturn {
  const [sessions, setSessions] = useState<SessionListResult | null>(null)
  const [currentSession, setCurrentSession] = useState<SessionInfo | null>(null)
  const [forkMessages, setForkMessages] = useState<ForkableMessage[]>([])

  const loadSessions = useCallback(async () => {
    try {
      const result = await api.listSessions()
      setSessions(result)
    } catch {
      setSessions(null)
    }
  }, [])

  const loadCurrentSession = useCallback(async () => {
    try {
      const info = await api.getCurrentSession()
      setCurrentSession(info)
    } catch {
      setCurrentSession(null)
    }
  }, [])

  const getForkMessages = useCallback(async (): Promise<ForkableMessage[]> => {
    try {
      const msgs = await api.getForkMessages()
      setForkMessages(msgs)
      return msgs
    } catch {
      setForkMessages([])
      return []
    }
  }, [])

  const forkAtEntry = useCallback(async (entryId: string, name: string) => {
    const result = await api.forkAtEntry(entryId, name)
    if (result.success) {
      await loadSessions()
      await loadCurrentSession()
    }
  }, [loadSessions, loadCurrentSession])

  const switchSession = useCallback(async (sessionPath: string) => {
    const result = await api.switchSession(sessionPath)
    if (result.success) {
      await loadSessions()
      await loadCurrentSession()
    }
    return result
  }, [loadSessions, loadCurrentSession])

  const newSession = useCallback(async (name: string, parentSessionPath?: string): Promise<boolean> => {
    const result = await api.newSession(parentSessionPath)
    if (result.success) {
      await api.renameSession(name)
      await loadSessions()
      await loadCurrentSession()
      return true
    }
    return false
  }, [loadSessions, loadCurrentSession])

  const renameSession = useCallback(async (name: string) => {
    const result = await api.renameSession(name)
    if (result.success) {
      await loadCurrentSession()
      await loadSessions()
    }
  }, [loadCurrentSession, loadSessions])

  const refresh = useCallback(async () => {
    await Promise.all([loadSessions(), loadCurrentSession()])
  }, [loadSessions, loadCurrentSession])

  const deleteSession = useCallback(async (sessionPath: string): Promise<boolean> => {
    const result = await api.deleteSession(sessionPath)
    if (result.success) {
      await loadSessions()
      return true
    }
    return false
  }, [loadSessions])

  const getForkPoints = useCallback(async (sessionPath: string): Promise<ForkPoint[]> => {
    try {
      return await api.getForkPoints(sessionPath)
    } catch {
      return []
    }
  }, [])

  const clearSession = useCallback(async (): Promise<boolean> => {
    try {
      const result = await api.clearSession()
      if (result.success) {
        await loadSessions()
        await loadCurrentSession()
        return true
      }
      return false
    } catch {
      return false
    }
  }, [loadSessions, loadCurrentSession])

  useEffect(() => {
    loadSessions()
    if (isConnected) {
      loadCurrentSession()
    }
  }, [isConnected, loadSessions, loadCurrentSession])

  useEffect(() => {
    const cleanup = window.api.onStateChanged((state) => {
      if (state.connected) {
        loadSessions()
        loadCurrentSession()
      }
    })
    return cleanup
  }, [loadSessions, loadCurrentSession])

  return {
    sessions,
    currentSession,
    forkMessages,
    loadSessions,
    forkAtEntry,
    switchSession,
    newSession,
    renameSession,
    deleteSession,
    getForkPoints,
    refresh,
    getForkMessages,
    clearSession,
  }
}

import { useEffect, useState, useCallback } from 'react'
import { usePiRpc } from './hooks/usePiRpc'
import { useSessionManager } from './hooks/useSessionManager'
import ChatView from './components/ChatView'
import InputBar from './components/InputBar'
import SessionSidebar from './components/SessionSidebar'
import { TokenUsageRing } from './components/TokenUsageRing'
import type { ViewMode } from './utils/compact-view'

function getDisplayName(session: { name: string | null; createdAt: string }): string {
  if (session.name) return session.name
  const d = new Date(session.createdAt)
  const month = d.toLocaleString('en', { month: 'short' })
  const day = d.getDate()
  const hh = String(d.getHours()).padStart(2, '0')
  const mm = String(d.getMinutes()).padStart(2, '0')
  return `${month} ${day} ${hh}:${mm}`
}

function App(): React.ReactElement {
  const { messages, isConnected, isStreaming, sendPrompt, abort, pendingUiRequests, respondToUiRequest, clearMessages, loadHistory, forkPoints, loadForkPoints, setOnAgentEnd, tokenUsage } = usePiRpc()
  const { sessions, currentSession, forkAtEntry, switchSession, newSession, renameSession, deleteSession, getForkMessages, clearSession, refresh } = useSessionManager(isConnected)
  const [error, setError] = useState<string | null>(null)
  const [sidebarCollapsed, setSidebarCollapsed] = useState(false)
  const [activeSessionPath, setActiveSessionPath] = useState<string | null>(null)
  const [viewMode, setViewMode] = useState<ViewMode>(() => {
    return (localStorage.getItem('xi-view-mode') as ViewMode) || 'normal'
  })

  const activeSession = activeSessionPath
    ? sessions?.projects?.flatMap(p => p.allSessions).find(s => s.filePath === activeSessionPath)
    : currentSession

  const activeSessionName = activeSession ? getDisplayName(activeSession) : null

  async function handleConnect(): Promise<void> {
    setError(null)
    const result = await window.api.start()
    if (!result.ok && result.error) {
      setError(result.error)
    }
    refresh()
  }

  // Auto-start Pi on mount
  useEffect(() => {
    handleConnect()
  }, [])

  const handleSwitchSession = useCallback(async (sessionPath: string) => {
    const prevPath = activeSessionPath
    setActiveSessionPath(sessionPath)
    const result = await switchSession(sessionPath)
    if (result.success) {
      clearMessages()
      await loadHistory()
      await loadForkPoints(sessionPath)
      await refresh()
    } else {
      setActiveSessionPath(prevPath)
    }
  }, [activeSessionPath, clearMessages, switchSession, loadHistory, loadForkPoints, refresh])

  const handleNewSession = useCallback(async (name: string) => {
    const parentPath = currentSession?.filePath
    clearMessages()
    const result = await newSession(name, parentPath)
    if (result) await refresh()
  }, [clearMessages, newSession, currentSession, refresh])

  const handleForkAtEntry = useCallback(async (entryId: string, name: string) => {
    clearMessages()
    await forkAtEntry(entryId, name)
    await loadHistory()
    await refresh()
  }, [clearMessages, forkAtEntry, loadHistory, refresh])

  const handleClearSession = useCallback(async () => {
    clearMessages()
    const ok = await clearSession()
    if (ok) {
      clearMessages()
      await loadHistory()
      await refresh()
      setActiveSessionPath(null)
    }
  }, [clearMessages, clearSession, loadHistory, refresh])

  useEffect(() => {
    if (isConnected) {
      loadHistory()
    }
  }, [isConnected, loadHistory])

  useEffect(() => {
    if (isConnected && currentSession?.filePath) {
      loadForkPoints(currentSession.filePath)
    }
  }, [isConnected, currentSession?.filePath, loadForkPoints])

  useEffect(() => {
    setOnAgentEnd(() => refresh)
  }, [setOnAgentEnd, refresh])

  useEffect(() => {
    function handleKeyDown(e: KeyboardEvent): void {
      if (e.key === 'Escape' && isStreaming) {
        abort()
      }
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [isStreaming, abort])

  useEffect(() => {
    const cleanup = window.api.onEvent((rawEvent) => {
      const evt = rawEvent as { type: string; error?: string; errorMessage?: string }
      if (evt.type === 'extension_error' && evt.error) {
        setError(`Extension error: ${evt.error}`)
      }
    })
    return cleanup
  }, [])

  return (
    <div className="flex h-screen w-screen overflow-hidden bg-white text-gray-900">
      <SessionSidebar
        sessions={sessions}
        currentSession={currentSession}
        onSwitchSession={handleSwitchSession}
        onNewSession={handleNewSession}
        onRenameSession={renameSession}
        onDeleteSession={deleteSession}
        isCollapsed={sidebarCollapsed}
        onToggleCollapse={() => setSidebarCollapsed(!sidebarCollapsed)}
      />

      <div className="flex flex-1 flex-col overflow-hidden">
        <div className="flex items-center justify-between border-b border-gray-200 bg-gray-50 px-4 pt-10 pb-2" style={{ WebkitAppRegion: 'drag' } as React.CSSProperties}>
          <div className="flex items-center gap-2" style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            {sidebarCollapsed && (
              <button
                onClick={() => setSidebarCollapsed(false)}
                className="rounded p-1 text-gray-500 hover:text-gray-700 hover:bg-gray-100 transition-colors"
                title="Show sessions"
              >
                <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                  <path strokeLinecap="round" strokeLinejoin="round" d="M4 6h16M4 12h16M4 18h16" />
                </svg>
              </button>
            )}
            <div className={`h-2 w-2 rounded-full ${isConnected ? 'bg-green-500' : 'bg-red-500'}`} />
            <span className="text-xs text-gray-600">
              {isConnected ? 'Pi Connected' : 'Pi Disconnected'}
            </span>
            {activeSessionName && (
              <>
                <span className="text-xs text-gray-700 font-medium border-l border-gray-300 pl-2">
                  {activeSessionName}
                </span>
                <button
                  onClick={handleClearSession}
                  className="rounded p-1 text-gray-400 hover:text-red-500 hover:bg-gray-100 transition-colors"
                  title="Clear conversation"
                >
                  <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                    <path strokeLinecap="round" strokeLinejoin="round" d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                </button>
              </>
            )}
            {isStreaming && (
              <span className="text-xs text-blue-600 animate-pulse">Streaming...</span>
            )}
            {error && (
              <span className="text-xs text-red-500" title={error}>Error</span>
            )}
          </div>
          <TokenUsageRing
            usedTokens={tokenUsage.totalTokens}
            contextWindowSize={tokenUsage.contextWindowSize}
            inputTokens={tokenUsage.inputTokens}
            outputTokens={tokenUsage.outputTokens}
            cacheReadTokens={tokenUsage.cacheReadTokens}
            totalCost={tokenUsage.totalCost}
          />
          <div className="flex items-center rounded-md border border-gray-200 bg-gray-100 p-0.5" style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            <button
              onClick={() => { localStorage.setItem('xi-view-mode', 'normal'); setViewMode('normal') }}
              className={`rounded px-2 py-0.5 text-xs font-medium transition-colors ${viewMode === 'normal' ? 'bg-gray-200 text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
              title="Full view"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 4h18M3 8h18M3 12h18M3 16h18M3 20h18" />
              </svg>
            </button>
            <button
              onClick={() => { localStorage.setItem('xi-view-mode', 'turn'); setViewMode('turn') }}
              className={`rounded px-2 py-0.5 text-xs font-medium transition-colors ${viewMode === 'turn' ? 'bg-gray-200 text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
              title="Turn view"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 5h18M6 9h12M3 13h18M6 17h12" />
              </svg>
            </button>
            <button
              onClick={() => { localStorage.setItem('xi-view-mode', 'outline'); setViewMode('outline') }}
              className={`rounded px-2 py-0.5 text-xs font-medium transition-colors ${viewMode === 'outline' ? 'bg-gray-200 text-gray-900 shadow-sm' : 'text-gray-500 hover:text-gray-700'}`}
              title="Outline view"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M3 7h18M3 12h18M3 17h18" />
              </svg>
            </button>
          </div>
          <div className="flex items-center gap-2" style={{ WebkitAppRegion: 'no-drag' } as React.CSSProperties}>
            {!isConnected && (
              <button
                onClick={handleConnect}
                className="rounded bg-blue-600 px-3 py-1 text-xs font-medium text-white hover:bg-blue-500"
              >
                Connect to Pi
              </button>
            )}
            {isStreaming && (
              <button
                onClick={abort}
                className="rounded bg-red-600 px-3 py-1 text-xs font-medium text-white hover:bg-red-500"
              >
                Stop (Esc)
              </button>
            )}
          </div>
        </div>

        <ChatView
          messages={messages}
          pendingUiRequests={pendingUiRequests}
          respondToUiRequest={respondToUiRequest}
          onSendPrompt={sendPrompt}
          onForkAtEntry={handleForkAtEntry}
          getForkMessages={getForkMessages}
          forkPoints={forkPoints}
          viewMode={viewMode}
        />

        <InputBar onSend={sendPrompt} disabled={!isConnected || isStreaming} />
      </div>
    </div>
  )
}

export default App

import { useState, useCallback, useEffect, useRef } from 'react'
import type { SessionListResult, SessionInfo, SessionTreeNode } from '../types/session'

interface SessionSidebarProps {
  sessions: SessionListResult | null
  currentSession: SessionInfo | null
  onSwitchSession: (sessionPath: string) => void
  onNewSession: (name: string) => void
  onRenameSession: (name: string) => void
  onDeleteSession: (sessionPath: string) => Promise<boolean>
  isCollapsed: boolean
  onToggleCollapse: () => void
}

function formatRelativeTime(isoTimestamp: string): string {
  const now = Date.now()
  const then = new Date(isoTimestamp).getTime()
  const diffMs = now - then
  const diffMin = Math.floor(diffMs / 60000)
  const diffHr = Math.floor(diffMs / 3600000)
  const diffDay = Math.floor(diffMs / 86400000)

  if (diffMin < 1) return 'just now'
  if (diffMin < 60) return `${diffMin}m ago`
  if (diffHr < 24) return `${diffHr}h ago`
  if (diffDay < 30) return `${diffDay}d ago`
  return new Date(isoTimestamp).toLocaleDateString()
}

function getDisplayName(session: SessionInfo): string {
  if (session.name) return session.name
  const d = new Date(session.createdAt)
  const month = d.toLocaleString('en', { month: 'short' })
  const day = d.getDate()
  const hh = String(d.getHours()).padStart(2, '0')
  const mm = String(d.getMinutes()).padStart(2, '0')
  return `${month} ${day} ${hh}:${mm}`
}

const SLOT_W = 16
const LINE_LEFT = 7

function isDescendantOf(node: SessionTreeNode, sessionPath: string | null): boolean {
  if (!sessionPath) return false
  if (node.session.filePath === sessionPath) return true
  return node.children.some((child) => isDescendantOf(child, sessionPath))
}

function GuideLine({ color }: { color: string }) {
  return (
    <div
      className="flex-shrink-0 relative pointer-events-none"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    >
      <div
        className="absolute"
        style={{
          left: LINE_LEFT,
          top: 0,
          bottom: 0,
          width: 1,
          backgroundColor: color,
        }}
      />
    </div>
  )
}

function GuideBranch({ color, branchColor, bottomColor }: { color: string; branchColor?: string; bottomColor?: string }) {
  const brColor = branchColor ?? color
  const btColor = bottomColor ?? color
  return (
    <div
      className="flex-shrink-0 relative pointer-events-none"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    >
      {/* 上半段竖线 + 圆角 + 水平分支：用 border 绘制，与 GuideElbow 同样的圆角效果 */}
      <div
        className="absolute"
        style={{
          left: LINE_LEFT,
          top: 0,
          height: '50%',
          width: SLOT_W - LINE_LEFT - 1,
          borderLeft: `1px solid ${color}`,
          borderBottom: `1px solid ${brColor}`,
          borderBottomLeftRadius: 4,
        }}
      />
      {/* 下半段竖线：从50%到底部，后续兄弟是否在 active path 上 */}
      <div
        className="absolute"
        style={{
          left: LINE_LEFT,
          top: '50%',
          bottom: 0,
          width: 1,
          backgroundColor: btColor,
        }}
      />
    </div>
  )
}

function GuideElbow({ color }: { color: string }) {
  return (
    <div
      className="flex-shrink-0 relative pointer-events-none"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    >
      <div
        className="absolute"
        style={{
          left: LINE_LEFT,
          top: 0,
          height: '50%',
          width: SLOT_W - LINE_LEFT - 1,
          borderLeft: `1px solid ${color}`,
          borderBottom: `1px solid ${color}`,
          borderBottomLeftRadius: 4,
        }}
      />
    </div>
  )
}

function GuideSlot() {
  return (
    <div
      className="flex-shrink-0"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    />
  )
}

function DotSlot({
  active,
  hasChildren,
  isExpanded,
  gutterActive,
}: {
  active: boolean
  hasChildren: boolean
  isExpanded: boolean
  gutterActive: boolean
}) {
  return (
    <div
      className="flex-shrink-0 flex flex-col items-center relative"
      style={{ width: SLOT_W, alignSelf: 'stretch' }}
    >
      <div className="flex items-center justify-center h-6">
        <div
          className={
            active
              ? 'w-2.5 h-2.5 rounded-full bg-blue-500 border-2 border-blue-500 flex-shrink-0'
              : 'w-2.5 h-2.5 rounded-full bg-white border-2 border-gray-300 group-hover:border-blue-500 flex-shrink-0'
          }
        />
      </div>
      {hasChildren && isExpanded && (
        <div
          className="absolute"
          style={{
            left: LINE_LEFT,
            top: 24,
            bottom: 0,
            width: 1,
            backgroundColor: gutterActive ? '#3b82f6' : '#e5e7eb',
          }}
        />
      )}
    </div>
  )
}

function SessionNode({
  node,
  ancestorLines,
  currentSessionPath,
  isOnActivePath,
  onSwitch,
  onRename,
  onDelete,
  onContextMenu,
  triggerRenamePath,
  onRenameTriggered,
}: {
  node: SessionTreeNode
  ancestorLines: { hasLine: boolean; color: string; branchColor?: string; bottomColor?: string }[]
  currentSessionPath: string | null
  isOnActivePath: boolean
  onSwitch: (path: string) => void
  onRename: (name: string) => void
  onDelete: (path: string) => Promise<boolean>
  onContextMenu: (e: React.MouseEvent, session: SessionInfo) => void
  triggerRenamePath: string | null
  onRenameTriggered: () => void
}): React.ReactElement {
  const [isExpanded, setIsExpanded] = useState(true)
  const [isRenaming, setIsRenaming] = useState(false)
  const [renameValue, setRenameValue] = useState(getDisplayName(node.session))
  const [confirmDelete, setConfirmDelete] = useState(false)
  const isActive = currentSessionPath === node.session.filePath
  const hasChildren = node.children.length > 0

  useEffect(() => {
    if (triggerRenamePath === node.session.filePath) {
      setIsRenaming(true)
      setRenameValue(getDisplayName(node.session))
      onRenameTriggered()
    }
  }, [triggerRenamePath, node.session.filePath, onRenameTriggered])

  const handleDoubleClick = useCallback(() => {
    setIsRenaming(true)
    setRenameValue(getDisplayName(node.session))
  }, [node.session])

  const handleRenameSubmit = useCallback(() => {
    const trimmed = renameValue.trim()
    if (trimmed && trimmed !== getDisplayName(node.session)) {
      onRename(trimmed)
    }
    setIsRenaming(false)
  }, [renameValue, node.session, onRename])

  const hasChildOnActivePath = node.children.some(
    (child) =>
      currentSessionPath === child.session.filePath ||
      isDescendantOf(child, currentSessionPath)
  )

  const gutterActive = hasChildOnActivePath

  const renderGuides = () => {
    if (ancestorLines.length === 0) return null
    return ancestorLines.map((entry, i) => {
      const isConnector = i === ancestorLines.length - 1
      if (isConnector) {
        if (entry.hasLine) {
          return <GuideBranch key={i} color={entry.color} branchColor={entry.branchColor} bottomColor={entry.bottomColor} />
        }
        return <GuideElbow key={i} color={entry.color} />
      }
      if (entry.hasLine) {
        return <GuideLine key={i} color={entry.color} />
      }
      return <GuideSlot key={i} />
    })
  }

  return (
    <div>
      <div
        className={`group flex items-center rounded cursor-pointer transition-colors ${
          isActive
            ? 'bg-gray-100 text-gray-900'
            : 'text-gray-600 hover:bg-gray-100/60 hover:text-gray-800'
        }`}
        onClick={() => onSwitch(node.session.filePath)}
        onDoubleClick={handleDoubleClick}
        onContextMenu={(e) => onContextMenu(e, node.session)}
      >
        {renderGuides()}
        <DotSlot
          active={isOnActivePath || isActive || node.session.isMain}
          hasChildren={hasChildren}
          isExpanded={isExpanded}
          gutterActive={gutterActive}
        />
        <div className="flex-1 flex items-center gap-1 py-1.5 pr-2 min-w-0">
          {isRenaming ? (
            <input
              autoFocus
              value={renameValue}
              onChange={(e) => setRenameValue(e.target.value)}
              onBlur={handleRenameSubmit}
              onKeyDown={(e) => {
                if (e.key === 'Enter') handleRenameSubmit()
                if (e.key === 'Escape') setIsRenaming(false)
              }}
              onClick={(e) => e.stopPropagation()}
              className="flex-1 min-w-0 bg-gray-100 rounded px-1 py-0.5 text-xs text-gray-900 outline-none border border-gray-300 focus:border-blue-500"
            />
          ) : (
            <span className="flex-1 truncate text-xs">
              {getDisplayName(node.session)}
            </span>
          )}

          <span className="flex-shrink-0 text-[10px] text-gray-400 opacity-0 group-hover:opacity-100 transition-opacity">
            {formatRelativeTime(node.session.createdAt)}
          </span>

          {hasChildren && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                setIsExpanded(!isExpanded)
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-gray-600 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title={isExpanded ? 'Collapse' : 'Expand'}
            >
              <svg
                className={`w-3 h-3 transition-transform ${isExpanded ? 'rotate-90' : ''}`}
                fill="currentColor"
                viewBox="0 0 20 20"
              >
                <path
                  fillRule="evenodd"
                  d="M7.21 14.77a.75.75 0 01.02-1.06L11.168 10 7.23 6.29a.75.75 0 111.04-1.08l4.5 4.25a.75.75 0 010 1.08l-4.5 4.25a.75.75 0 01-1.06-.02z"
                  clipRule="evenodd"
                />
              </svg>
            </button>
          )}

          {node.session.parentSessionPath && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                onSwitch(node.session.parentSessionPath!)
              }}
              className="flex-shrink-0 rounded px-0.5 py-0.5 text-gray-400 hover:text-blue-500 hover:bg-gray-100 opacity-0 group-hover:opacity-100 transition-colors"
              title="Go to parent session"
            >
              <svg className="w-3.5 h-3.5" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M5 15l7-7 7 7" />
              </svg>
            </button>
          )}

          {!isActive && !node.session.isMain && (
            <button
              onClick={(e) => {
                e.stopPropagation()
                if (confirmDelete) {
                  onDelete(node.session.filePath)
                  setConfirmDelete(false)
                } else {
                  setConfirmDelete(true)
                }
              }}
              onBlur={() => setConfirmDelete(false)}
              className={`flex-shrink-0 rounded px-1 py-0.5 text-[10px] opacity-0 group-hover:opacity-100 transition-colors ${
                confirmDelete
                  ? 'bg-red-600 text-white opacity-100'
                  : 'text-gray-400 hover:text-red-500 hover:bg-gray-100'
              }`}
            >
              {confirmDelete ? 'Del' : 'x'}
            </button>
          )}
        </div>
      </div>

      {hasChildren && isExpanded && (
        <div>
          {node.children.map((child, i) => {
            const childIsActivePath =
              currentSessionPath === child.session.filePath ||
              isDescendantOf(child, currentSessionPath)
            const laterSiblingOnActivePath = node.children
              .slice(i + 1)
              .some(
                (sibling) =>
                  currentSessionPath === sibling.session.filePath ||
                  isDescendantOf(sibling, currentSessionPath)
              )
            const branchColor = childIsActivePath ? '#3b82f6' : '#e5e7eb'            // 水平分支：当前节点是否 active
            const continuationColor = laterSiblingOnActivePath ? '#3b82f6' : '#e5e7eb' // 下半段竖线：后续兄弟是否 active
            const onPath = childIsActivePath || laterSiblingOnActivePath
            const verticalTopColor = onPath ? '#3b82f6' : '#e5e7eb'                  // 上半段竖线：整条线是否在 active path 上
            const newAncestorLines = [
              ...ancestorLines.map((entry) => ({
                hasLine: entry.hasLine,
                color: onPath ? '#3b82f6' : entry.color,
                branchColor: entry.branchColor,
                bottomColor: entry.bottomColor,
              })),
              {
                hasLine: i < node.children.length - 1,
                color: verticalTopColor,
                branchColor: branchColor,
                bottomColor: i < node.children.length - 1 ? continuationColor : undefined,
              },
            ]
            return (
              <SessionNode
                key={child.session.filePath}
                node={child}
                ancestorLines={newAncestorLines}
                currentSessionPath={currentSessionPath}
                isOnActivePath={childIsActivePath}
                onSwitch={onSwitch}
                onRename={onRename}
                onDelete={onDelete}
                onContextMenu={onContextMenu}
                triggerRenamePath={triggerRenamePath}
                onRenameTriggered={onRenameTriggered}
              />
            )
          })}
        </div>
      )}
    </div>
  )
}

function SessionSidebar({
  sessions,
  currentSession,
  onSwitchSession,
  onNewSession,
  onRenameSession,
  onDeleteSession,
  isCollapsed,
  onToggleCollapse,
}: SessionSidebarProps): React.ReactElement {
  const [isCreating, setIsCreating] = useState(false)
  const [newSessionName, setNewSessionName] = useState('')
  const [sidebarWidth, setSidebarWidth] = useState(() => {
    const saved = localStorage.getItem('xi-sidebar-width')
    return saved ? parseInt(saved, 10) : 260
  })
  const [isResizing, setIsResizing] = useState(false)
  const [contextMenu, setContextMenu] = useState<{
    x: number
    y: number
    session: SessionInfo
  } | null>(null)
  const [triggerRenamePath, setTriggerRenamePath] = useState<string | null>(null)

  const sidebarWidthRef = useRef(sidebarWidth)
  sidebarWidthRef.current = sidebarWidth

  const resizeStartRef = useRef<{ startX: number; startWidth: number } | null>(null)

  const projects = sessions?.projects ?? []
  const projectName = projects[0]?.projectPath.split('/').pop() ?? 'Sessions'
  const root = projects[0]?.root ?? null

  const handleCreateSession = useCallback(() => {
    const trimmed = newSessionName.trim()
    if (!trimmed) return
    onNewSession(trimmed)
    setNewSessionName('')
    setIsCreating(false)
  }, [newSessionName, onNewSession])

  const handleContextMenu = useCallback((e: React.MouseEvent, session: SessionInfo) => {
    e.preventDefault()
    e.stopPropagation()
    setContextMenu({ x: e.clientX, y: e.clientY, session })
  }, [])

  const handleRenameTriggered = useCallback(() => {
    setTriggerRenamePath(null)
  }, [])

  useEffect(() => {
    if (!contextMenu) return

    const handleClick = () => setContextMenu(null)
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Escape') setContextMenu(null)
    }

    document.addEventListener('click', handleClick)
    document.addEventListener('keydown', handleKeyDown)

    return () => {
      document.removeEventListener('click', handleClick)
      document.removeEventListener('keydown', handleKeyDown)
    }
  }, [contextMenu])

  useEffect(() => {
    if (!isResizing) return

    const handleMouseMove = (e: MouseEvent) => {
      if (!resizeStartRef.current) return
      const delta = e.clientX - resizeStartRef.current.startX
      const newWidth = Math.min(480, Math.max(180, resizeStartRef.current.startWidth + delta))
      setSidebarWidth(newWidth)
    }

    const handleMouseUp = () => {
      setIsResizing(false)
      resizeStartRef.current = null
      localStorage.setItem('xi-sidebar-width', String(sidebarWidthRef.current))
      document.body.style.cursor = ''
      document.body.style.userSelect = ''
    }

    document.body.style.cursor = 'col-resize'
    document.body.style.userSelect = 'none'
    window.addEventListener('mousemove', handleMouseMove)
    window.addEventListener('mouseup', handleMouseUp)

    return () => {
      window.removeEventListener('mousemove', handleMouseMove)
      window.removeEventListener('mouseup', handleMouseUp)
    }
  }, [isResizing])

  const handleResizeStart = useCallback((e: React.MouseEvent) => {
    e.preventDefault()
    setIsResizing(true)
    resizeStartRef.current = { startX: e.clientX, startWidth: sidebarWidth }
  }, [sidebarWidth])

  if (isCollapsed) {
    return (
      <div className="flex flex-col items-center w-12 bg-gray-50 border-r border-gray-200 pt-10 pb-3">
        <button
          onClick={onToggleCollapse}
          className="rounded p-2 text-gray-400 hover:text-gray-600 hover:bg-gray-100 transition-colors"
          title="Expand sidebar"
        >
          <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
            <path strokeLinecap="round" strokeLinejoin="round" d="M13 5l7 7-7 7M5 5l7 7-7 7" />
          </svg>
        </button>
      </div>
    )
  }

  return (
    <div
      className="relative flex flex-col bg-gray-50 border-r border-gray-200 overflow-hidden"
      style={{ width: `${sidebarWidth}px` }}
    >
      <div className="flex items-center justify-between px-3 pt-10 pb-3 border-b border-gray-200">
        <span className="text-xs font-semibold uppercase tracking-wider text-gray-500 truncate">{projectName}</span>
        <div className="flex items-center gap-1 flex-shrink-0">
          <button
            onClick={() => { setIsCreating(true); setNewSessionName('') }}
            className="rounded p-1 text-gray-400 hover:text-gray-600 hover:bg-gray-100 transition-colors"
            title="New session"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M12 4v16m8-8H4" />
            </svg>
          </button>
          <button
            onClick={onToggleCollapse}
            className="rounded p-1 text-gray-400 hover:text-gray-600 hover:bg-gray-100 transition-colors"
            title="Collapse sidebar"
          >
            <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
              <path strokeLinecap="round" strokeLinejoin="round" d="M11 19l-7-7 7-7M19 19l-7-7 7-7" />
            </svg>
          </button>
        </div>
      </div>

      {isCreating && (
        <div className="flex items-center gap-1 border-b border-gray-200 px-3 py-2">
          <input
            autoFocus
            value={newSessionName}
            onChange={(e) => setNewSessionName(e.target.value)}
            onKeyDown={(e) => {
              if (e.key === 'Enter') handleCreateSession()
              if (e.key === 'Escape') setIsCreating(false)
            }}
            placeholder="Session name"
            className="flex-1 min-w-0 rounded border border-gray-300 bg-white px-2 py-1 text-xs text-gray-900 outline-none focus:border-blue-500"
          />
          <button
            onClick={handleCreateSession}
            disabled={!newSessionName.trim()}
            className="rounded bg-blue-600 px-2 py-1 text-xs font-medium text-white hover:bg-blue-500 disabled:opacity-40 disabled:cursor-not-allowed"
          >
            Create
          </button>
        </div>
      )}

      <div className="flex-1 overflow-y-auto py-2">
        {projects.length === 0 || !root ? (
          <div className="px-3 py-6 text-center text-xs text-gray-600">
            No sessions found
          </div>
        ) : (
          <SessionNode
            node={root}
            ancestorLines={[]}
            currentSessionPath={currentSession?.filePath ?? null}
            isOnActivePath={true}
            onSwitch={onSwitchSession}
            onRename={onRenameSession}
            onDelete={onDeleteSession}
            onContextMenu={handleContextMenu}
            triggerRenamePath={triggerRenamePath}
            onRenameTriggered={handleRenameTriggered}
          />
        )}
      </div>

      <div
        className="absolute top-0 right-0 w-1 h-full cursor-col-resize hover:w-1.5 hover:bg-blue-500/30 transition-all z-10"
        onMouseDown={handleResizeStart}
      />

      {contextMenu && (
        <div
          className="fixed z-50 bg-white border border-gray-200 rounded-lg shadow-lg py-1 text-xs min-w-[140px]"
          style={{ left: contextMenu.x, top: contextMenu.y }}
          onClick={(e) => e.stopPropagation()}
        >
          <div
            className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
            onClick={() => {
              setTriggerRenamePath(contextMenu.session.filePath)
              setContextMenu(null)
            }}
          >
            Rename
          </div>
          {contextMenu.session.parentSessionPath && (
            <div
              className="px-3 py-1.5 hover:bg-gray-100 cursor-pointer"
              onClick={() => {
                onSwitchSession(contextMenu.session.parentSessionPath!)
                setContextMenu(null)
              }}
            >
              Go to parent
            </div>
          )}
          {contextMenu.session.filePath !== currentSession?.filePath && !contextMenu.session.isMain && (
            <div
              className="px-3 py-1.5 hover:bg-red-50 cursor-pointer text-red-600"
              onClick={() => {
                onDeleteSession(contextMenu.session.filePath)
                setContextMenu(null)
              }}
            >
              Delete
            </div>
          )}
        </div>
      )}
    </div>
  )
}

export default SessionSidebar

